SELECT c.id, c.consultation_no, c.patient_id, c.type, c.status, c.department, c.chief_complaint, c.medical_summary, c.fee, c.payment_status, c.scheduled_time, c.end_time, c.cancel_reason, c.reject_reason, c.create_time, c.update_time, p.name AS patient_name, p.age AS patient_age, p.gender AS patient_gender FROM consultation c LEFT JOIN patient p ON c.patient_id = p.id
AND c.status = #{status}
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR c.consultation_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM consultation c LEFT JOIN patient p ON c.patient_id = p.id
AND c.status = #{status}
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR c.consultation_no LIKE CONCAT('%', #{keyword}, '%'))
